'use client';
/**
 * Navbar.tsx — Client Component
 * ─────────────────────────────────────────────────────────────────────────────
 * Migrated from react-router-dom (useLocation / Link) to Next.js equivalents:
 *   - usePathname()  replaces useLocation().pathname
 *   - useRouter()    replaces useNavigate()
 *   - <Link href>    replaces <Link to>
 *
 * Theme toggle now uses next-themes (useTheme) instead of the custom
 * useTheme hook that read/wrote localStorage directly.
 *
 * Everything else (scroll-aware opacity, mobile drawer, active link
 * highlighting, hero-transparent mode) is preserved 1-for-1.
 */

import { useEffect, useRef, useState } from 'react';
import Link                            from 'next/link';
import { usePathname }                 from 'next/navigation';
import { useTheme }                   from 'next-themes';
import { Moon, Sun, ExternalLink, Menu, X } from 'lucide-react';
import { cn }                          from '@/lib/utils';
import { DORM_HOMEPAGE }              from '@/data/dormInfo';

const NAV_LINKS = [
  { href: '/',           label: '홈' },
  { href: '/dorms',      label: '기숙사' },
  { href: '/calculator', label: '점수 계산기' },
];

export function Navbar() {
  const pathname               = usePathname();
  const { resolvedTheme, setTheme } = useTheme();

  const toggleTheme = () =>
    setTheme(resolvedTheme === 'dark' ? 'light' : 'dark');

  // ── Scroll-aware visibility ────────────────────────────────────────────────
  const [isHidden, setIsHidden] = useState(false);
  const [isOnHero, setIsOnHero] = useState(true);
  const lastScrollY = useRef(0);

  useEffect(() => {
    const onScroll = () => {
      const y = window.scrollY;
      setIsHidden(y > lastScrollY.current && y > 120);
      setIsOnHero(y < 60);
      lastScrollY.current = y;
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Reset hero-mode when navigating away from home
  useEffect(() => {
    if (pathname !== '/') setIsOnHero(false);
    else setIsOnHero(window.scrollY < 60);
  }, [pathname]);

  // ── Mobile menu ────────────────────────────────────────────────────────────
  const [mobileOpen, setMobileOpen] = useState(false);
  useEffect(() => setMobileOpen(false), [pathname]);

  const isHero = isOnHero && pathname === '/';

  return (
    <>
      <nav
        className={cn(
          'navbar',
          isHidden  && 'hidden-up',
          isHero    && 'on-hero'
        )}
      >
        <div className="container mx-auto px-4 h-full flex items-center justify-between">

          {/* Logo */}
          <Link
            href="/"
            className={cn(
              'font-extrabold text-base tracking-tight transition-colors duration-200',
              isHero ? 'text-white' : 'text-foreground'
            )}
          >
            아주대 긱사 어디가
            <span
              className={cn(
                'ml-1.5 text-xs font-semibold px-1.5 py-0.5 rounded-md',
                isHero
                  ? 'bg-white/20 text-white/80'
                  : 'bg-primary/10 text-primary'
              )}
            >
              Beta
            </span>
          </Link>

          {/* Desktop nav links */}
          <div className="hidden md:flex items-center gap-1">
            {NAV_LINKS.map(({ href, label }) => {
              const isActive =
                href === '/' ? pathname === '/' : pathname.startsWith(href);
              return (
                <Link
                  key={href}
                  href={href}
                  className={cn(
                    'nav-link px-3 py-1.5 rounded-lg',
                    isActive && 'active',
                    isHero
                      ? 'text-white/70 hover:text-white hover:bg-white/10'
                      : 'hover:bg-muted'
                  )}
                >
                  {label}
                </Link>
              );
            })}
          </div>

          {/* Right controls */}
          <div className="flex items-center gap-2">
            <button
              onClick={toggleTheme}
              aria-label="테마 전환"
              className={cn(
                'w-8 h-8 rounded-lg flex items-center justify-center transition-colors duration-200',
                isHero
                  ? 'text-white/70 hover:text-white hover:bg-white/10'
                  : 'text-muted-foreground hover:text-foreground hover:bg-muted'
              )}
            >
              {resolvedTheme === 'dark'
                ? <Sun  className="w-4 h-4" />
                : <Moon className="w-4 h-4" />
              }
            </button>

            <a
              href={DORM_HOMEPAGE}
              target="_blank"
              rel="noopener noreferrer"
              className={cn(
                'hidden md:inline-flex items-center gap-1.5 text-xs font-semibold',
                'px-3.5 py-2 rounded-lg transition-all duration-200',
                isHero
                  ? 'bg-white/[0.12] text-white/80 hover:bg-white/[0.2] hover:text-white border border-white/20'
                  : 'bg-primary text-primary-foreground hover:bg-primary/90 shadow-sm hover:shadow-md'
              )}
            >
              <ExternalLink className="w-3 h-3" />
              공식 홈페이지
            </a>

            <button
              onClick={() => setMobileOpen((v) => !v)}
              aria-label="메뉴 열기"
              className={cn(
                'md:hidden w-8 h-8 rounded-lg flex items-center justify-center transition-colors duration-200',
                isHero
                  ? 'text-white/70 hover:text-white hover:bg-white/10'
                  : 'text-muted-foreground hover:text-foreground hover:bg-muted'
              )}
            >
              {mobileOpen ? <X className="w-4 h-4" /> : <Menu className="w-4 h-4" />}
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile drawer */}
      {mobileOpen && (
        <div
          className="fixed inset-0 z-40 md:hidden"
          onClick={() => setMobileOpen(false)}
        >
          <div className="absolute inset-0 bg-black/30 backdrop-blur-sm" />
          <div
            className="absolute top-[var(--nav-height)] left-0 right-0 bg-background/95
                       backdrop-blur-xl border-b border-border shadow-xl animate-slide-down"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="container mx-auto px-4 py-4 flex flex-col gap-1">
              {NAV_LINKS.map(({ href, label }) => {
                const isActive =
                  href === '/' ? pathname === '/' : pathname.startsWith(href);
                return (
                  <Link
                    key={href}
                    href={href}
                    className={cn(
                      'px-4 py-3 rounded-xl text-sm font-medium transition-colors',
                      isActive
                        ? 'bg-primary/[0.08] text-primary'
                        : 'text-muted-foreground hover:text-foreground hover:bg-muted'
                    )}
                  >
                    {label}
                  </Link>
                );
              })}
              <a
                href={DORM_HOMEPAGE}
                target="_blank"
                rel="noopener noreferrer"
                className="mt-2 flex items-center gap-2 px-4 py-3 rounded-xl
                           text-sm font-semibold bg-primary text-primary-foreground"
              >
                <ExternalLink className="w-3.5 h-3.5" />
                공식 홈페이지 바로가기
              </a>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
